PRAGMA foreign_keys = ON;

-- Часть 13 из 28. Существующие тайтлы не перезаписываются.

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894e0","title":"Batman Vol. 13: City of Bane Part 2","author":"Том Кинг","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003616069/140/4e05/Tom_King__Batman_Vol._13_City_of_Bane_Part_2.jpg","isbn":"1779502842, 9781779502841","publisher":"DC Comics","pubDate":"2020","language":"Английский","series":"","genres":[],"annotation":"Eisner Award winner Tom King reunites with Mikel Janin as he continues his bestselling Batman run. Batman returns to Gotham just in time for the epic showdown with Bane!  The bad guys thought they had it made with Bane in control, but with Batman back in Gotham they''ll be reminded what justice feels like...and how it hurts when it hits you in the face. With Catwoman at his side, the Caped Crusader is looking to take down Bane''s army and reclaim his city.  But is the Dark Knight Detective ready to take on the foe who broke him worse than any other that came before? And what else stands in Batman''s way, to put an obstacle between him and his enemy? Tread lightly, Batman, because not only do the lives of your son and trusted friends hang in the balance, but your entire home could collapse. Batman and his allies have a choice: let Bane stay in power and guarantee the city''s survival, or risk everything to break free!  Collects Batman #80-85.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-03","rating":3,"review":"","added":9999584,"hdCover":""},{"id":"09894df","title":"Batman Vol. 12: City of Bane Part 1","author":"Том Кинг","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003616068/140/11a0/Tom_King__Batman_Vol._12_City_of_Bane_Part_1.jpg","isbn":"140129958X, 9781401299583","publisher":"DC Comics","pubDate":"2020","language":"Английский","series":"Tales from Verania","genres":[],"annotation":"Eisner Award winner Tom King reunites with Mikel Janin as he continues his best-selling Batman run. Batman faces his most personal battle yet as he is locked in a life or death battle with... his father?  Ever since Batman''s impending wedding went south on him, the Caped Crusader has had the sinking suspicion that there has been someone lurking in the shadows setting events into motion. After the attempted assassination of Nightwing he starts to question his commitment to his war on crime, his relationships and even his own sanity.  There has been an unseen hand orchestrating these events. And while the true villain has yet to reveal himself, his minions are starting to step forward and break the Bat down once and for all--beginning with Thomas Wayne, the Batman from the Flashpoint Universe!  Collects Batman #75-79.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":3,"review":"","added":9999583,"hdCover":""},{"id":"09894de","title":"Batman Secret Files","author":"","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005562444/140/a595/__Batman_Secret_Files.jpg","isbn":"","publisher":"DC Comics","pubDate":"2018","language":"Английский","series":"DC Universe","genres":[],"annotation":"Delve into Batman’s case histories and discover brand-new stories by some of comics’ most exciting talents. The BATMAN team of Tom King and Mikel Janin provides a framing sequence, setting up our hand-picked teams of creators to take a look at Bat-mysteries past and present. Featuring a bevy of Batman villains, including a look at how the Scarecrow’s fear toxin affects the common man, and a special story written by Tom Taylor with art by Brad Walker that  teams the Dark Knight Detective with Detective Chimp.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":4.5,"review":"","added":9999582,"hdCover":""},{"id":"09894dd","title":"Batman, Volume 11: The Fall and the Fallen","author":"Тони С. Дэниел,Mikel Janin,Том Кинг","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003404515/140/1912/__Batman_Volume_11_The_Fall_and_the_Fallen.jpg","isbn":"1779501609, 9781779501608","publisher":"DC Comics","pubDate":"2020","language":"Английский","series":"Batman Rebirth","genres":[],"annotation":"Eisner Award winner Tom King reunites with Mikel Janin as he continues his best-selling Batman run. Batman faces his most personal battle yet as he is locked in a life or death battle with... his father?  Ever since Batman''s impending wedding went south on him, the Caped Crusader has had the sinking suspicion that there has been someone lurking in the shadows setting events into motion. After the attempted assassination of Nightwing he starts to question his commitment to his war on crime, his relationships and even his own sanity.  There has been an unseen hand orchestrating these events. And while the true villain has yet to reveal himself, his minions are starting to step forward and break the Bat down once and for all--beginning with Thomas Wayne, the Batman from the Flashpoint Universe!  Collects Batman #70-74 and Secret Files #2","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":2.5,"review":"","added":9999581,"hdCover":""},{"id":"09894dc","title":"Batman Vol. 10: Knightmares","author":"Аманда Коннер,Jorge Fornes,Том Кинг,Yannick Paquette","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003189267/140/5c77/__Batman_Vol._10_Knightmares.jpg","isbn":"1779501587, 9781779501585","publisher":"DC Comics","pubDate":"2019","language":"Английский","series":"DC Rebirth","genres":[],"annotation":"Eisner Award winner Tom King''s explosive Batman run continues as he plunges the Dark Knight''s world further into a spiral of madness from which he may never return.  There are strange goings-on in the dark alleys of Gotham City, mysteries that will require a different skill set than the Caped Crusader''s if he''s going to stop the whole city from succumbing to the darkness. Still reeling from the attacks on his Bat-Family and reputation, the Dark Knight looks to track down the mysterious operator has been lurking behind the scenes in Gotham.  Featuring a slew of masterful artists including Mister Miracle collaborator Mitch Gerads, Tom King and crew take the Dark Knight on his wildest ride yet.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":2.5,"review":"","added":9999580,"hdCover":""},{"id":"09894db","title":"Кризис героев","author":"Клей Манн,Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005139465/140/ca7d/__Krizis_geroev.jpg","isbn":"978-5-389-18579-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"С ПОДОБНЫМ КРИЗИСОМ ГЕРОИ ЕЩЕ НЕ СТАЛКИВАЛИСЬ!  Добро пожаловать в Убежище! Это строго засекреченный, единственный в своем роде реабилитационный центр для супергероев, построенный Бэтменом, Суперменом и Чудо-Женщиной. Здесь с помощью самых передовых технологий супергерои залечивают свои раны и травмы, восстанавливаясь после бесконечной битвы со злом, чтобы затем с новыми силами вернуться на поле боя.  Однако мир Убежища разрушен кошмарным событием – средь бела дня там произошло массовое убийство. И кто же главные подозреваемые? Принцесса-Клоунесса Харли Квинн и путешественник во времени Бустер Голд, сбежавшие с места преступления.  В процессе поисков виновных становится ясно, что все намного серьезнее, чем казалось на первый взгляд. И если Бэтмен, Супермен и Чудо-Женщина не раскроют это преступление, все секреты Убежища – а вместе с ними и подробности жизни каждого героя во Вселенной, – будут подвергнуты риску разоблачения…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":4,"review":"","added":9999579,"hdCover":""},{"id":"09894da","title":"Вселенная DC. Rebirth. Бэтмен. Книга 7. Холодные дни","author":"Том Кинг","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005527614/140/e636/Tom_King__Vselennaya_DC._Rebirth._Betmen._Kniga_7._Holodnye_dni.jpg","isbn":"978-5-389-18495-4","publisher":"Азбука","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Свадьба века позади. Бэтмен прошел долгий путь к алтарю ради Женщины-Кошки… и теперь вся его жизнь перевернулась с ног на голову.  Но это был лишь первый удар. Брюса вызывают в жюри присяжных на суд по делу Мистера Фриза, где Уэйн вынужден задаться вопросами о чрезмерном могуществе своего альтер-эго: верные ли решения принимает Темный Рыцарь, когда его мысли затуманены после недавних событий? Какое влияние он оказывает на жителей родного города? И может быть, герою вообще пора повесить свой плащ на гвоздь?..  Тем временем в Готэм возвращается русский наемник по прозвищу КГБист, да и Пингвин проявляет весьма подозрительную активность. Сердце и душа Брюса изранены — хватит ли ему сил справиться со старыми противниками и выжить на фоне глубочайшего личного кризиса?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":4,"review":"","added":9999578,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894d9","title":"Новая Росомаха. Том 3","author":"Том Тейлор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004003338/140/b5d7/Tom_Tejlor__Novaya_Rosomaha._Tom_3.jpg","isbn":"978-5-04-111614-9","publisher":"Эксмо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Дакен, настоящий сын Логана, похищен, и его \"\"сестре\"\" придётся взять след! Но куда он приведёт? Лора попадёт в учреждение, где её создали, и узнает много страшных секретов из прошлого Росомахи. Кто такие Сироты Икс и какие цели они преследуют? Новая Росомаха пообещала не убивать, но сможет ли она сдержать клятву, когда на кону будут стоять её с Дакеном жизни? А после жуткое открытие ждёт Гэбби, и единственным, кому она сможет довериться, окажется Дэдпул! Но поможет ли болтливый наёмник отомстить или всё станет только хуже? И наконец, вы узнаете, что ждёт Росомаху в будущем… Старуха Лора? Спустя много лет супергероям удалось создать утопию, в которой больше нет места преступности. Лора больше не Росомаха, а справедливая королева Мадрипура! Какое же зло сможет заставить её снова надеть костюм?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":4,"review":"","added":9999577,"hdCover":""},{"id":"09894d8","title":"Веном. Мстительный Токсин!","author":"Каллен Банн,Каленн Банн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005615853/140/6f64/__Venom._Mstitelnyj_Toksin.jpg","isbn":"978-5-91878-367-2","publisher":"Фантастика Книжный Клуб","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Флэш Томпсон прощается с Нью-Йорком и отправляется в свой новый дом — Филадельфию, планируя стать её защитником. Расставаясь в «Большом яблоке» с Питером Паркером, Бетти Брант и другими друзьями, Юджин надеется на светлое будущее в городе братской любви, но горизонт затягивает токсичное облако — возвращается враг из прошлого Венома! Симбиот Токсин и его безумный носитель Эдди Брок выслеживают Флэша до Филли и начинают охоту! Но противостояние оборачивается угрозой для обоих существ... Сумеют ли Агент Веном и Брок удерживать своих партнёров под контролем достаточно долго, чтобы покончить с Убийцами симбиотов?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":2.5,"review":"","added":9999576,"hdCover":""},{"id":"09894d7","title":"Новая Росомаха. Том 2 (сборник)","author":"Том Тейлор,Леонард Кирк,Ник Вирелла,Джибриль Мориссетт-Фэн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003834484/140/3324/__Novaya_Rosomaha._Tom_2_sbornik.jpg","isbn":"978-5-04-108433-2","publisher":"Эксмо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Лора долго пыталась доказать, что она не просто оружие, но теперь её руки по локоть в крови! Попытки скрыться от правосудия приведут её в прекрасный и опасный Мадрипур, край белоснежных песчаных пляжей, изысканной кухни и жестоких убийц. Там её ждут злодей из далёкого прошлого, пираты, Ангел, Гамбит, Ник Фьюри и разрушительные приключения!  Сразу после райского острова Росомахе предстоит отправиться в далёкий, холодный космос, ведь в Нью-Йорке потерпел крушение инопланетный корабль, единственный пассажир которого привёз на Землю опасный вирус и перед смертью успел произнести только одно имя: Лора Кинни! Росомаха объединится со Стражами Галактики и отправится за много световых лет от родной планеты, чтобы найти ответ на вопрос: кто же отправил ей столь смертоносное послание?  В книгу входят комиксы «Новая Росомаха» #13–24. Над серией работали Том Тэйлор, Ник Вирелла, Джибриль Мориссетт-Фэн, Скотт Ханна, Майкл Гарленд, Хесус Абуртов, Леонард Кирк, Кори Хемшер, Марк Диринг, Терри Палло, Крис Сотомайор и Эрик Арсинега.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":3.5,"review":"","added":9999575,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894d6","title":"Новая Росомаха. Том 1 (сборник)","author":"Том Тейлор","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003453907/140/19ff/Tom_Tejlor__Novaya_Rosomaha._Tom_1_sbornik.jpg","isbn":"978-5-04-107448-7","publisher":"Эксмо","pubDate":"2019","language":"Русский","series":"Ужастики","genres":["Комиксы","манга","графические романы"],"annotation":"ТЕПЕРЬ ОНА ЛУЧШАЯ В СВОЁМ ДЕЛЕ! Х-23 БЫЛА СОЗДАНА, ЧТОБЫ СТАТЬ ОРУЖИЕМ. И была им какое-то время. Но Лора Кинни сбежала от этой жизни благодаря своему наставнику, Логану, оригинальному Росомахе. Теперь, когда он погиб, Лора чтит его память, став Новой Росомахой. Но скоро её ждёт встреча с людьми, чьи лица она знает как своё собственное. БУКВАЛЬНО. Эти люди в смятении, и чтобы облегчить их ношу, Лора обратится за помощью к Доктору Стрэнджу и Осе! А также: прошлое отбрасывает большую тень. Лора узнает это на своём опыте, когда встретится не с кем иным, как со Стариком Логаном! Он пришёл в этот мир из царства антиутопии и разрухи и готов затянуть туда всех, включая саму Лору. Она останется героем или же сдастся под натиском мрачной судьбы? В книгу входят комиксы \"Новая Росомаха\" #1–12. Над серией работали Том Тэйлор, Дэвид Лопез, Дэвид Наварро, Марсио Такара и Иг Гуара.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":4,"review":"","added":9999574,"hdCover":""},{"id":"09894d5","title":"Джон Константин. Hellblazer. Страх и ненависть (сборник)","author":"Гарт Эннис,Стив Диллон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004634811/140/8635/__Dzhon_Konstantin._Hellblazer._Strah_i_nenavist_sbornik.jpg","isbn":"978-5-389-18321-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Джон Константин перехитрил и смертельную болезнь, и самого владыку Ада. Но однажды утром он замечает дату в газете и вспоминает, какой сегодня день: ему исполнилось сорок. Его подруге Кит пришлось срочно уехать в Белфаст, и он уже готов напиться до беспамятства в гордом одиночестве. Однако не тут-то было: старый приятель Повелитель танца устраивает в честь Константина грандиозное торжество, пригласив и Затанну, и саму Болотную Тварь.  Впрочем, даже обыграв по всем статьям архангела Гавриила и Национальный фронт, Константин оказывается «на дне всех дней», и ему придется сделать поистине сверхчеловеческое усилие, чтобы победить Короля Вампиров и начать долгий путь наверх...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":4.5,"review":"","added":9999573,"hdCover":""},{"id":"09894d4","title":"Психушка Джокера 2: Глиноликий","author":"Кевин Шиник","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002086925/140/2e0f/Kevin_Shinik__Psihushka_Dzhokera_2_Glinolikij.jpg","isbn":"7-61941-29574-9-00111","publisher":"DC Comics","pubDate":"2010","language":"Русский","series":"Психушка Джокера 2","genres":[],"annotation":"История Глиноликого началась, когда после не самой удачной премьеры одного из фильмов с Базилем Карло в роли монстра, «Кошмар» (или «Террор») буквально сошел с экрана. Некогда вымышленный персонаж обрел самую настоящую форму: Базиль превратился в инертную массу, способную менять свою форму. За неуважение к собственной персоне Базиль строго покарал всех, кто находился поблизости.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":4.5,"review":"","added":9999572,"hdCover":""},{"id":"09894d3","title":"Joker''s Asylum II: Killer Croc #1","author":"Майк Рэйч","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002085195/140/920f/Majk_Rejch__Joker039s_Asylum_II_Killer_Croc_1.jpg","isbn":"","publisher":"DC Comics","pubDate":"2010","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":4,"review":"","added":9999571,"hdCover":""},{"id":"09894d2","title":"Joker''s Asylum II: Mad Hatter #1","author":"Билл Сенкевич,Марк Уорк,Лендри Куин Уолкер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002085118/140/bd7b/__Joker039s_Asylum_II_Mad_Hatter_1.jpg","isbn":"978-1-4012-2980-1","publisher":"DC Comics","pubDate":"2010","language":"Английский","series":"Joker''s Asylum","genres":["Комиксы","манга","графические романы"],"annotation":"Top creators lend their talents to a new installment of THE JOKER''S ASYLUM – a special month-long, weekly series of one-shots starring the greatest villains in Batman''s rogues gallery.Each issue is narrated by The Joker and tells a special stand-alone story that gives readers an inside look into the insane lives of The Dark Knight''s greatest adversaries! This batch of tense tales spotlights The Riddler, Harley Quinn, Mad Hatter, Clayface and Killer Croc! Can you stand the madness?!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":2.5,"review":"","added":9999570,"hdCover":""},{"id":"09894d1","title":"Joker''s Asylum II: Harley Quinn","author":"James Patrick, Joe Quinones","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003861429/140/9bd8/James_Patrick_Joe_Quinones__Joker039s_Asylum_II_Harley_Quinn.jpg","isbn":"","publisher":"DC","pubDate":"2010","language":"Английский","series":"Joker''s Asylum II","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":2,"review":"","added":9999569,"hdCover":""},{"id":"09894d0","title":"Joker''s Asylum II: The Riddler #1","author":"Питер Кэллоуэй","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002882573/140/a1cb/Piter_Kellouej__Joker039s_Asylum_II_The_Riddler_1.jpg","isbn":"","publisher":"DC Comics","pubDate":"2010","language":"Английский","series":"Joker''s Asylum II","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":3.5,"review":"","added":9999568,"hdCover":""},{"id":"09894cf","title":"Психушка Джокера. Двуликий. Дважды Двуликий!","author":"Дэвид Хайн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005543577/140/94fe/Devid_Hajn__Psihushka_Dzhokera._Dvulikij._Dvazhdy_Dvulikij.jpg","isbn":"978-5-389-17710-9","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Холман и Харви похожи как близнецы. Только внешне. У обоих чудовищно обезображена одна сторона лица. Холман пострадал на пожаре и считает спасителем Бэтмена. Ханта спасла от падения в пропасть сила духа, вера в лучшее, любимая женщина и мотивационный коучинг. Хант хочет стать другом собрату по несчастью. Харви тоже был таким, пока его лицо не обезобразила кислота.  Двуликий давно в аду, куда ангелы, твердящие о спасении, доброте, любви и прощении, спускаются больше для самоутверждения. Значит это не ангелы, а такие же посланцы тьмы, как Тёмный рыцарь. Раз так – надо преподать пожарному урок, показать, что такое истинное двуличие. Двуликий не хочет, чтобы Холман Хант становился ему другом. Кого выберет спасти Хант, если подбросить монету – свою девушку, кого он так любит, или того, кого считает героем?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-02","rating":4,"review":"","added":9999567,"hdCover":""},{"id":"09894ce","title":"Joker''s Asylum: Scarecrow #1","author":"Джо Харрис","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002086936/140/e551/Dzho_Harris__Joker039s_Asylum_Scarecrow_1.jpg","isbn":"","publisher":"DC Comics","pubDate":"2008","language":"","series":"Joker''s Asylum","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3,"review":"","added":9999566,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894cd","title":"Психушка Джокера. Ядовитый Плющ. Сорванный цветок","author":"Дж. Т. Крул","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004634814/140/097b/Dzh._T._Krul__Psihushka_Dzhokera._Yadovityj_Plyusch._Sorvannyj_tsvetok.jpg","isbn":"978-5-389-17709-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Джокер, прикармливая хищные цветы в своём садике, с нескрываемым сарказмом ко всем участникам истории травит байку о том, как Ядовитый Плющ схлестнулась с нечистыми на руку застройщиками. В погоне за лёгкими деньгами дельцы задумали уничтожить природный ландшафт ради стройки, но вместо зелёных банкнот получили весточку от зеленоглазой смерти. Даже Бэтмену не по зубам ростки Плюща, а уж Джокер без инсектицида под рукой не вспоминает тот случай...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3.5,"review":"","added":9999565,"hdCover":""},{"id":"09894cc","title":"Психушка Джокера. Пингвин. Тот, кто смеется последним!","author":"Джейсон Аарон,Джейсон Пирсон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003829887/140/f8db/__Psihushka_Dzhokera._Pingvin._Tot_kto_smeetsya_poslednim.jpg","isbn":"978-5-389-17708-6","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"«Психушка Джокера» - серия отдельных историй о готэмских злодеях, рассказанных от лица завсегдатая Аркхема – Джокера. Десяток ваншотов представил самых ярких представителей преступного мира, с кем когда-либо встречался Джокер. Помимо Пингвина, в «Психушке Джокера» побывали Харли Квинн, Загадочник, Двуликий, Убийца Крок и другие. Лучшие выпуски из линейки будут изданы «Азбукой».  Освальд Кобблпот, он же Пингвин. Что о нем расскажет Джокер? Он поведает историю о том, как Оззи однажды влюбился и что из этого вышло… С детства над несуразно выглядящим Освальдом Кобблпотом насмехались люди. Никому это не сошло с рук. Увлекшись местью, Пингвин стал забывать о том, каково это – быть человеком, заботиться о ком-то, хотеть с кем-то быть вместе. Однажды, в минуту душевных терзаний, Пингвин спас девушку Вайолет. Он привязался к ней, а она не смеялась над ним из-за внешности и была добра. Им хорошо вместе. Сможет ли Пингвин простить миру обиды и стать просто Освальдом? Или пути назад нет и он должен всегда оставаться тем, кто смеется последним? Джокер точно знает, как все было. И как будет…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4,"review":"","added":9999564,"hdCover":""},{"id":"09894cb","title":"Джон Константин. Hellblazer. Опасные привычки (сборник)","author":"Гарт Эннис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003353976/140/4e35/Gart_Ennis__Dzhon_Konstantin._Hellblazer._Opasnye_privychki_sbornik.jpg","isbn":"978-5-389-17108-4","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Джон Константин… Жулик, шутник, один из умнейших и храбрейших оккультистов в истории. Долгие годы он вел борьбу против исчадий Ада, однако смерть явилась за Джоном отнюдь не из Преисподней…  Рак легких в поздней стадии – такой неутешительный диагноз ставят Константину. Лечения нет. Многие другие бы отчаялись и повесили руки, но только не Джон: всеми возможными и невозможными способами хитрый маг цепляется за жизнь. Вот только рак – не очередной демон. Это чудовище куда страшнее. От него нельзя избавиться, просто начертив пентаграмму на полу или прочитав заклинание. Казалось бы, хуже быть не может – но вдобавок ко всему Джон умудряется разозлить Первого из Падших, нового повелителя Ада…  Впереди Константина ждет самая тяжелая битва в его жизни. Справится ли он?..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4.5,"review":"","added":9999563,"hdCover":""},{"id":"09894ca","title":"Психушка Джокера: Джокер","author":"Arvid Nelson","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002087980/140/2b0d/Arvid_Nelson__Psihushka_Dzhokera_Dzhoker.jpg","isbn":"B001BSSE8K","publisher":"DC Comics","pubDate":"2008","language":"Русский","series":"Психушка Джокера","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":2.5,"review":"","added":9999562,"hdCover":""},{"id":"09894c9","title":"Джон Константин. Hellblazer. Ньюкасл","author":"Джэми Делано","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003353977/140/d199/Dzhemi_Delano__Dzhon_Konstantin._Hellblazer._Nyukasl.jpg","isbn":"978-5-389-17107-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2019","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Молодой Джон с командой друзей совершает свои первые шаги в оккультизме. До них дошли вести о странных событиях в Ньюкасле, куда начинающие «маги» и решили наведаться. Взломав дверь клуба, где они когда-то тусовались, герои увидели на полу гору расчлененных трупов и маленькую девочку. Ну а дальше...  Как мы уже говорили, история «Ньюкасла» имела свои последствия для каждого из членов команды, ведь Ад потом заберет каждого из них. И это одна из важных причин прочитать «Ньюкасл» - именно этот комикс подарил нам основу той истории, которая в дальнейшем зародила большой пласт комиксов о Константине, и не только.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4.5,"review":"","added":9999561,"hdCover":""},{"id":"09894c8","title":"Собакистан. Щенки","author":"Виталий Терлецкий,Катя","type":"Манга","cover":"https://s1.livelib.ru/boocover/1005582541/140/42c4/__Sobakistan._Schenki.jpg","isbn":"978-5-6042551-6-2","publisher":"Терлецки Комикс","pubDate":"2020","language":"Русский","series":"Собакистан","genres":["Манга"],"annotation":"Коричневый большеносый Вуф и долговязая Ханни Свит Лав — щенки нового времени. Они ходят в школу, почти всегда слушаются родителей и ведут собственное секретное расследование. Главный вопрос, который их интересует — кто такой товарищ Дружок?  Долгожданное продолжение хита «Собакистан», вошедшего в шорт-лист премии «НОС-2020».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3.5,"review":"","added":9999560,"hdCover":""}]');

