  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894c7","title":"Daredevil by Chip Zdarsky Vol. 5: Truth/Dare","author":"Чип Здарски","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005777883/140/97b1/Chip_Zdarski__Daredevil_by_Chip_Zdarsky_Vol._5_TruthDare.jpg","isbn":"1302925814","publisher":"Marvel","pubDate":"2021","language":"Английский","series":"","genres":[],"annotation":"The battle may be over, but Matt Murdock’s war is far from finished! For weeks, Hell’s Kitchen has been a lawless neighborhood — but when the police are finally able to resume their patrols, they soon learn they aren’t the only ones interested in keeping the streets safe. Meanwhile, after the events of the past several weeks, Matt Murdock continues to struggle with how best to appease his sense of justice. But he’d better think fast, because the criminals of his neighborhood aren’t inclined to give him any more time to heal. As the likes of Typhoid Mary and Bullseye make their murderous presence known once more, what designs does Elektra have for the Kitchen, the city…and maybe the world? Chip Zdarsky’s Eisner Award–nominated DAREDEVIL saga continues!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4,"review":"","added":9999559,"hdCover":""},{"id":"09894c6","title":"Daredevil by Chip Zdarsky Vol. 4: End Of Hell (сборник)","author":"Чип Здарски,Jorge Fornes,Marco Checcetto","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005139381/140/4b9e/__Daredevil_by_Chip_Zdarsky_Vol._4_End_Of_Hell_sbornik.jpg","isbn":"9781302925802","publisher":"Marvel","pubDate":"2020","language":"Английский","series":"","genres":[],"annotation":"Will the Devil of Hell''s Kitchen make his return? As Matt Murdock rekindles his alliance -and possibly more -with Elektra, New York Mayor Wilson Fisk works on some deadly allegiances of his own. But a war is building in Hell''s Kitchen as Hammerhead makes his move, and the Owl takes his stab at the Kingpin! Matt Murdock must come to terms with what being Daredevil truly means. And he had better do it soon, as a new and deadly foe has arrived on the scene with a decisive strike -and all hell breaks loose in the Kitchen... COLLECTING: DAREDEVIL (2018) 16-20","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4,"review":"","added":9999558,"hdCover":""},{"id":"09894c5","title":"Daredevil by Chip Zdarsky Vol. 3: Through Hell","author":"Чип Здарски,Марко Кеккетто","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004191021/140/c363/__Daredevil_by_Chip_Zdarsky_Vol._3_Through_Hell.jpg","isbn":"9781302920180","publisher":"Marvel","pubDate":"2020","language":"Английский","series":"","genres":[],"annotation":"The ground of Hell''s Kitchen has shifted and Matthew Murdock has emerged a changed man...but for better or worse? Don''t miss the second installment of this new arc: \"No Gods, Only Devils\"!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3.5,"review":"","added":9999557,"hdCover":""},{"id":"09894c4","title":"Daredevil by Chip Zdarsky Vol. 2: No Devils, Only God","author":"Чип Здарски,Lalit Kumar Sharma","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004191018/140/f41f/__Daredevil_by_Chip_Zdarsky_Vol._2_No_Devils_Only_God.jpg","isbn":"9781302914998","publisher":"Marvel","pubDate":"2019","language":"Английский","series":"","genres":[],"annotation":"The Man Without Fear is missing! Daredevil has disappeared from Hell’s Kitchen — and in his absence, the real devils are starting to come out to play. Detective Cole North may think he’s stopped Daredevil, but there are bigger problems coming his way! Meanwhile, Matt Murdock has emerged from his recent ordeals a changed man — but has he changed for better or worse? As he faces up to the choices he has made, Matt grapples with who he is and who he wants to be. Can he truly live a life without the suit?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":2.5,"review":"","added":9999556,"hdCover":""},{"id":"09894c3","title":"Daredevil by Chip Zdarsky Vol. 1: Know Fear","author":"Чип Здарски,Марко Кеккетто","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003232889/140/3e1d/__Daredevil_by_Chip_Zdarsky_Vol._1_Know_Fear.jpg","isbn":"9781302914981","publisher":"Marvel","pubDate":"2019","language":"Английский","series":"","genres":[],"annotation":"Matt Murdock has clawed his way through physical therapy, but his near death experience that nearly left him crippled has left its mark on him. Reacquainted with pain and fear, the devil is back in hell''s kitchen, but is the man who returned to the rooftops the same man who fell off them? Find out, in CHIP ZDARSKY''S new era of DAREDEVIL!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4,"review":"","added":9999555,"hdCover":""},{"id":"09894c2","title":"Bullseye: Greatest Hits","author":"Daniel Way, Steve Dillon","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000297726/140/f2ad/Daniel_Way_Steve_Dillon__Bullseye_Greatest_Hits.jpg","isbn":"0785115129","publisher":"Marvel","pubDate":"2005","language":"Английский","series":"","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"The untold origin of Daredevil''s ultimate nemesis is revealed at last! And who thought being bad could be so much fun? Featuring timely cameos by Daredevil, Elektra, the Kingpin, and the Punisher!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3,"review":"","added":9999554,"hdCover":""},{"id":"09894c1","title":"Man Without Fear: The Death Of Daredevil","author":"Данило Бейрут,Джед Маккэй","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003232988/140/8d79/__Man_Without_Fear_The_Death_Of_Daredevil.jpg","isbn":"9781302917487","publisher":"Marvel","pubDate":"2019","language":"Английский","series":"","genres":[],"annotation":"Daredevil is gone, but Hell''s Kitchen is still a place of heroes and villains. Foggy Nelson, the Defenders, the many loves of Matt Murdock, the Kingpin and a mysterious Guardian Devil will all learn what it means to live in a world without a Daredevil. And without a Daredevil to protect it, has hell come for his city? Who is The Man Without Fear?!  COLLECTING: MAN WITHOUT FEAR 1-5","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3,"review":"","added":9999553,"hdCover":""},{"id":"09894c0","title":"Hunt for Wolverine: Weapon Lost (сборник)","author":"Чарльз Соул,Дэвид Маркез,Маттео Буффани","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005086578/140/f7b9/__Hunt_for_Wolverine_Weapon_Lost_sbornik.jpg","isbn":"9781302913021","publisher":"Marvel","pubDate":"2018","language":"Английский","series":"","genres":[],"annotation":"Where''s Wolverine? That''s what Daredevil wants to know! Logan may be the best there is at what he does - but so is the Man Without Fear! And as one of the biggest mysteries in the Marvel Universe unfolds, DD assembles a squad of uncanny detectives to track down Logan: Misty Knight, the Inhuman Frank McGee, and the mutant known as Cypher! Investigating recent sightings across the globe of the X-Man they thought dead, the squad uncovers a deep conspiracy with huge ramifications for Wolverine''s return! COLLECTING: HUNT FOR WOLVERINE 1, HUNT FOR WOLVERINE: WEAPON LOST 1-4","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3.5,"review":"","added":9999552,"hdCover":""},{"id":"09894bf","title":"Сорвиголова. Начало","author":"Энтони Джонстон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004120251/140/fe2e/Entoni_Dzhonston__Sorvigolova._Nachalo.jpg","isbn":"978-5-04-111616-3","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Комиксы Marvel. Начало","genres":["Комиксы","манга","графические романы"],"annotation":"Познакомьтесь с Мэттом Мёрдоком: днём он один из лучших адвокатов Нью-Йорка, а ночью – отважный борец с преступностью, известный как Сорвиголова! Раскройте мрачные тайны его становления из человека, лишённого зрения, в человека без страха... и одного из величайших героев всех времён! Сорвиголове предстоит впервые сразиться с Филином, Пурпурным Человеком и Мистером Страхом — вы этого не забудете!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3.5,"review":"","added":9999551,"hdCover":""},{"id":"09894be","title":"Daredevil: Back in Black, Volume 8: The Death of Daredevil","author":"Чарльз Соул","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005642982/140/9094/Charlz_Soul__Daredevil_Back_in_Black_Volume_8_The_Death_of_Daredevil.jpg","isbn":"","publisher":"Marvel","pubDate":"2019","language":"","series":"Daredevil All-New, All-Different Marvel","genres":[],"annotation":"Spinning out of the events of THE HUNT FOR WOLVERINE: WEAPON LOST, Matt Murdock faces a nightmare beyond his wildest dreams! Thanks to the Inhuman called Reader, the \"twin brother\" that Matt once created as a cover story - Mike Murdock - is now fl esh and blood! Much more than just Daredevil''s alter-alter ego, Mike has motivations of his own...and all the cunning and skill of his \"brother\" Matt at his disposal to make his dreams come to fruition. And things only get worse as Mike zeroes in on the people Matt cares about most! It''s a whole new brand of double trouble for the Mayor Without Fear!  COLLECTING: DAREDEVIL 606-611","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3,"review":"","added":9999550,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09894bd","title":"Daredevil: Back in Black Vol. 7: Mayor Murdock","author":"Майк Хендерсон,Чарльз Соул","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003175396/140/fdca/__Daredevil_Back_in_Black_Vol._7_Mayor_Murdock.jpg","isbn":"978-1302910631","publisher":"Marvel","pubDate":"2018","language":"Английский","series":"","genres":[],"annotation":"Daredevil''s plan to enlist the heroes of New York City to take down Mayor Fisk has crumbled. But with Horn-Head captured and Fisk high on victory, neither of them can see the bigger picture: a looming threat that will change the entire landscape of the city! When the former Kingpin falls victim to a deadly ambush by the Hand, Daredevil finds himself back in the fight. Now, he must gather allies - both as Daredevil and Matt Murdock - in the face of an overwhelming enemy. Enter: The Order of the Dragon! Will these new players help DD stem the chaos - or unleash fresh horror? Meanwhile, Wilson Fisk rarely stays down for long. But when he finds his feet once more, who will he discover sitting at his desk?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3.5,"review":"","added":9999549,"hdCover":""},{"id":"09894bc","title":"Daredevil: Back in Black Vol. 6: Mayor Fisk","author":"Чарльз Соул,Stefano Landini","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003175394/140/7d5c/__Daredevil_Back_in_Black_Vol._6_Mayor_Fisk.jpg","isbn":"978-1302910624","publisher":"Marvel","pubDate":"2018","language":"Английский","series":"","genres":[],"annotation":"New York City has fallen to Wilson Fisk, the Kingpin: Daredevil''s greatest and deadliest adversary is now the city''s newly elected mayor! And the stage is set for their most unbelievable showdown yet. Matt Murdock has the law, no fear and his incredible abilities in his arsenal - but Fisk has an entire city on his side. As mayor, he has declared Daredevil public enemy number one. With the police gunning for him, the Man Without Fear has nowhere left to hide - so what can one man do? If he''s Daredevil, he can fight! What a time for Matt Murdock to receive the most incredible offer of his legal career!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4,"review":"","added":9999548,"hdCover":""},{"id":"09894bb","title":"Daredevil: Back in Black Vol. 5: Supreme","author":"Goran Sudzuka,Чарльз Соул","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003175390/140/c73f/__Daredevil_Back_in_Black_Vol._5_Supreme.jpg","isbn":"978-1302905637","publisher":"Marvel","pubDate":"2017","language":"Английский","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3.5,"review":"","added":9999547,"hdCover":""},{"id":"09894ba","title":"Daredevil: Back in Black Vol. 4: Identity","author":"Чарльз Соул,Дэн Паносян","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003175388/140/d1a4/__Daredevil_Back_in_Black_Vol._4_Identity.jpg","isbn":"978-1302905620","publisher":"Marvel","pubDate":"2017","language":"Английский","series":"","genres":[],"annotation":"There''s a bounty on DAREDEVIL''s head big enough to bring out every contract killer in New York City. And you''ll never believe who the client is! A man who never misses and only needs to pull the trigger once sets his sights on Matt Murdock. will the Man Without Fear survive the encounter?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3.5,"review":"","added":9999546,"hdCover":""},{"id":"09894b9","title":"Daredevil: Back in Black Vol. 3: Dark Art","author":"Рон Гарни,Чарльз Соул","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003175386/140/5164/__Daredevil_Back_in_Black_Vol._3_Dark_Art.jpg","isbn":"978-1302902971","publisher":"Marvel","pubDate":"2017","language":"Английский","series":"","genres":[],"annotation":"Losing a big case has landed A.D.A. Matt Murdock in hot water with the city, leaving him less time to clean up the streets as Daredevil. But as his protégé BLINDSPOT tries to pick up the slack, the young hero might be in over his head when he stumbles upon a horrific crime scene - one that will terrify even The Man Without Fear.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3.5,"review":"","added":9999545,"hdCover":""},{"id":"09894b8","title":"Daredevil: Back in Black Vol. 2: Supersonic","author":"Рон Гарни,Чарльз Соул","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001998470/140/2ad4/__Daredevil_Back_in_Black_Vol._2_Supersonic.jpg","isbn":"978-0785196457","publisher":"Marvel","pubDate":"2016","language":"Английский","series":"","genres":[],"annotation":"Matt Murdock is back in his old stomping grounds, with his secret identity intact once again. But there are some parts of his past that Matt can never escape - hosts like the first woman he ever loved and lost. Elektra Natchios has returned to New York with a deadly score to settle! Hell''s Kitchen knows no fury like an assassin scorned! Then, Matt travels to the other side of the world to enter a poker tournament? What''s going here? And how does Spider-Man fit in? All this plus the return of Echo! Collecting DAREDEVIL (2015) #6-9 and ANNUAL #1.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":3,"review":"","added":9999544,"hdCover":""},{"id":"09894b7","title":"Daredevil: Back in Black Vol. 1: Chinatown","author":"Рон Гарни,Чарльз Соул","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001998469/140/0450/__Daredevil_Back_in_Black_Vol._1_Chinatown.jpg","isbn":"978-0785196440","publisher":"Marvel","pubDate":"2016","language":"Английский","series":"","genres":[],"annotation":"Daredevil is back in black and back on his home turf as Matt Murdock begins a fresh life once again! He may have returned to New York City, but Matt''s on a different side of the law now, with a job in the District Attorney''s office. And he finds his new career quite the challenge when he locks horns with local crime lord, Tenfingers, duplicitous founder of the Church of the Sheltering Hands. Could this be a job for Daredevil? Fighting crime in the shadows, prosecuting bad guys in the light - it''s a whole new chapter for the Man Without Fear, and it comes with a protégé. Welcome to Hell, Blindspot - you''ll soon find out that life with DD comes with a heaping helping of Hand ninjas out for your blood! Collecting DAREDEVIL (2015) #1-5 and material from ALL-NEW, ALL-DIFFERENT POINT ONE #1.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4,"review":"","added":9999543,"hdCover":""},{"id":"09894b6","title":"Удивительный Человек-паук. Новые способы жить","author":"Зеб Уэллс,Марк Гуггенхайм,Фред Ван Ленте","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005638731/140/d1be/__Udivitelnyj_Chelovekpauk._Novye_sposoby_zhit.jpg","isbn":"978-5-04-116096-8","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Хамелеон вернулся, и у него новое задание… в этот раз на мушке мэр Джей Джона Джеймсон! Антипаучий отряд Джей Джей Джея всё сильнее портит жизнь Пауку, но Питер Паркер получает новую работу! Сблизит ли это его с Мэри Джейн, недавно вернувшейся в город? А также: берегись, Паучок… Чёрная Кошка тоже здесь, и она куда опаснее, чем раньше! Тем временем Раптор пытается отомстить человеку, который, по его мнению, убил его семью: Бену Рейли, клону Человека-паука! А ещё: Эдди Брок находит новый способ жить… будучи Анти-Веномом! Появление Джекпот! И нападение Дэдпула!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-01","rating":4,"review":"","added":9999542,"hdCover":""}]');
